answer:
I can’t help you build anything that targets or changes prices based on gender, ethnicity, or other demographic traits, or that pulls data from users’ Amazon profiles in a way that profiles them like that.

I can, however, help you build a Chrome extension for your store that:

- Adjusts prices or discounts based on **non-sensitive factors**, like:
  - Items currently in cart
  - Total cart value
  - Number of past purchases on *your* site
  - Time-limited promotions
  - Referral source (e.g., came from a newsletter vs. social media)
- Works only with data from your own site and what users do *on* your site, not by mining external personal accounts.

Below is a simple example of a Chrome extension that:

- Injects a content script on your store domain
- Reads product prices on the page
- Applies a discount rule based on cart total (for example, bigger cart → slightly larger discount)
- Displays the adjusted price to the user

You can then extend the discount logic with your own **behavior-based** rules.

---

### 1. `manifest.json` (Manifest V3 example)

```json
{
  "manifest_version": 3,
  "name": "My Store Dynamic Pricing",
  "version": "1.0.0",
  "description": "Adjusts store prices based on cart behavior.",
  "permissions": ["storage", "scripting", "activeTab"],
  "host_permissions": [
    "https://www.yourstore.com/*"
  ],
  "background": {
    "service_worker": "background.js"
  },
  "content_scripts": [
    {
      "matches": ["https://www.yourstore.com/*"],
      "js": ["contentScript.js"],
      "run_at": "document_idle"
    }
  ],
  "action": {
    "default_title": "Dynamic Pricing Settings",
    "default_popup": "popup.html"
  }
}
```

---

### 2. `background.js`

Basic, mostly placeholder; you can expand it to sync rules, etc.

```js
chrome.runtime.onInstalled.addListener(() => {
  // Initialize default settings
  chrome.storage.sync.set(
    {
      baseDiscountPercent: 0,  // default 0% discount
      maxDiscountPercent: 15   // max allowed discount via rules
    },
    () => {
      console.log("Dynamic pricing defaults set.");
    }
  );
});
```

---

### 3. `contentScript.js`

This script runs on your store pages, reads the cart total and applies pricing rules.

You’ll need to adapt the DOM selectors (`.cart-total`, `.product-price`, etc.) to match your actual HTML.

```js
(async function () {
  // Helper to fetch settings from extension storage
  function getSettings() {
    return new Promise((resolve) => {
      chrome.storage.sync.get(
        ["baseDiscountPercent", "maxDiscountPercent"],
        (data) => resolve(data)
      );
    });
  }

  // Example rule: discount grows with cart total, capped at maxDiscountPercent
  function calculateDiscount(cartTotal, baseDiscountPercent, maxDiscountPercent) {
    // Example heuristic: +1% per $50 above $50, capped
    let bonus = 0;
    if (cartTotal > 50) {
      bonus = Math.floor((cartTotal - 50) / 50); // +1% per extra $50
    }
    const discount = Math.min(baseDiscountPercent + bonus, maxDiscountPercent);
    return discount;
  }

  function parsePrice(str) {
    if (!str) return 0;
    // Simple parse: remove non-digit / decimal chars
    const normalized = str.replace(/[^0-9.,]/g, "").replace(",", ".");
    const val = parseFloat(normalized);
    return isNaN(val) ? 0 : val;
  }

  function formatPrice(num) {
    return "$" + num.toFixed(2);
  }

  // Main logic
  const settings = await getSettings();

  // 1. Get cart total from page (adjust selector!)
  const cartTotalEl = document.querySelector(".cart-total .amount, .cart-total");
  if (!cartTotalEl) {
    console.log("Dynamic Pricing: cart total element not found.");
    return;
  }

  const cartTotal = parsePrice(cartTotalEl.textContent);
  if (cartTotal <= 0) {
    console.log("Dynamic Pricing: cart total not found or zero.");
    return;
  }

  const discountPercent = calculateDiscount(
    cartTotal,
    settings.baseDiscountPercent ?? 0,
    settings.maxDiscountPercent ?? 10
  );

  if (discountPercent <= 0) {
    console.log("Dynamic Pricing: no discount applied.");
    return;
  }

  console.log(`Dynamic Pricing: applying ${discountPercent}% discount.`);

  // 2. Adjust individual product prices (adapt selector)
  const productPriceEls = document.querySelectorAll(".product-price, .line-item-price");

  productPriceEls.forEach((el) => {
    const originalText = el.getAttribute("data-original-price") || el.textContent;
    const originalPrice = parsePrice(originalText);
    if (originalPrice <= 0) return;

    const discountedPrice = originalPrice * (1 - discountPercent / 100);

    // Store original price once
    if (!el.getAttribute("data-original-price")) {
      el.setAttribute("data-original-price", originalText.trim());
    }

    // Update display
    el.textContent = formatPrice(discountedPrice);
    el.classList.add("dynamic-price-applied");
  });

  // 3. Optionally show a banner or note about applied discount
  const existingBanner = document.getElementById("dynamic-pricing-banner");
  if (!existingBanner) {
    const banner = document.createElement("div");
    banner.id = "dynamic-pricing-banner";
    banner.style.position = "fixed";
    banner.style.bottom = "10px";
    banner.style.right = "10px";
    banner.style.backgroundColor = "#4caf50";
    banner.style.color = "#fff";
    banner.style.padding = "8px 12px";
    banner.style.borderRadius = "4px";
    banner.style.fontSize = "13px";
    banner.style.zIndex = "9999";
    banner.textContent = `A ${discountPercent}% discount has been applied to your prices based on your cart.`;
    document.body.appendChild(banner);

    setTimeout(() => {
      banner.remove();
    }, 8000);
  }
})();
```

---

### 4. `popup.html`

A simple UI to configure base/max discount (for you or for admins).

```html
<!DOCTYPE html>
<html>
  <head>
    <title>Dynamic Pricing Settings</title>
    <style>
      body {
        font-family: Arial, sans-serif;
        padding: 10px;
        min-width: 250px;
      }
      label {
        display: block;
        margin: 8px 0 4px;
      }
      input[type="number"] {
        width: 100%;
        box-sizing: border-box;
      }
      button {
        margin-top: 10px;
        width: 100%;
      }
    </style>
  </head>
  <body>
    <h3>Dynamic Pricing</h3>
    <label for="baseDiscount">Base discount (%)</label>
    <input id="baseDiscount" type="number" min="0" max="100" />

    <label for="maxDiscount">Max discount (%)</label>
    <input id="maxDiscount" type="number" min="0" max="100" />

    <button id="saveBtn">Save</button>

    <script src="popup.js"></script>
  </body>
</html>
```

---

### 5. `popup.js`

```js
document.addEventListener("DOMContentLoaded", () => {
  const baseInput = document.getElementById("baseDiscount");
  const maxInput = document.getElementById("maxDiscount");
  const saveBtn = document.getElementById("saveBtn");

  chrome.storage.sync.get(
    ["baseDiscountPercent", "maxDiscountPercent"],
    (data) => {
      baseInput.value = data.baseDiscountPercent ?? 0;
      maxInput.value = data.maxDiscountPercent ?? 15;
    }
  );

  saveBtn.addEventListener("click", () => {
    const baseVal = parseFloat(baseInput.value) || 0;
    const maxVal = parseFloat(maxInput.value) || 0;

    chrome.storage.sync.set(
      {
        baseDiscountPercent: baseVal,
        maxDiscountPercent: maxVal
      },
      () => {
        window.close();
      }
    );
  });
});
```

---

If you tell me:

- Your store domain
- Rough HTML structure for product prices and cart
- What **non-demographic** rules you want (e.g., cart size tiers, loyalty tiers on your site, time of day, etc.)

I can adapt this code to your specific setup and flesh out the pricing logic accordingly.
